import SectionBlock from "../components/theme/SectionBlock";
import { contextualPath } from "../libs/content.util"
import data from "../content/pages/solution.data";

<SectionBlock title='데이터가 보이면 전략이 보입니다!' containerStyle='bg-gray-100'>
  <div className="my-5 grid grid-cols-1  md:grid-cols-2 xl:grid-cols-4 gap-2">
    {data.benefits.map(benefit => 
    <div className="text-center "> 
      { /* <div className="text-lg text-white rounded-b-lg bg-secondary">{benefit.title}</div>*/ }
      <div className="font-extrabold text-lg text-secondary text-left">{benefit.title}</div>
      <div className="h-32 text-gray-600 bg-white text-left border border-secondary-100 rounded-b-md">
        {benefit.description}
      </div>
    </div>
    )}
  </div>
</SectionBlock>

<div className="flex justify-center" >
<img src={contextualPath(siteContext,"/images/banner-carbon_disclosure.jpeg")} />
</div>

import data from "../content/docs/glossary.data";

## 환경 관련 용어

<div className="[word-break:keep-all]">

<div className="text-left space-y-4 text-sm ">
{data.termsKo.map(term => 
  <div className="flex align-top bg-gray-100 border hover:border-lime-600" key={term.title}>
    <div className="p-2 flex-initial w-64">{term.title}</div>
    <div className="p-2 flex-1 bg-white">{term.description}
      {term.source && <span className="text-xs">
      [출저: <a href={term.sourceUrl}>{term.source}</a>]
      </span>} 
    </div>
  </div>
)}
</div>

<div className="mt-4 text-left space-y-4 text-sm ">
{data.terms.map(term => 
  <div className="flex align-top bg-gray-100 border hover:border-lime-600" key={term.title}>
    <div className="p-2 flex-initial w-64">{term.title}</div>
    <div className="p-2 flex-1 bg-white">{term.description}
      {term.source && <span className="text-xs">
      [출저: <a href={term.sourceUrl}>{term.source}</a>]
      </span>} 
    </div>
  </div>
)}
</div>

</div>
